from pathlib import Path

root = Path(r"C:\Users\Gebruiker\Rezzerv_Github")

pre = root / "backend/app/receipt_ingestion/preprocessing/receipt_image_preprocessing.py"
req = root / "backend/requirements.txt"

pre.write_text('from __future__ import annotations\n\nfrom dataclasses import asdict, dataclass, field\nfrom io import BytesIO\nimport os\nfrom pathlib import Path\nfrom typing import Any\n\nfrom PIL import Image, ImageOps\n\ntry:\n    import cv2\n    import numpy as np\nexcept Exception:\n    cv2 = None\n    np = None\n\ntry:\n    from rembg import remove as rembg_remove\nexcept Exception:\n    rembg_remove = None\n\n\nIMAGE_SUFFIXES = {".jpg", ".jpeg", ".png", ".webp", ".bmp"}\nALPHA_THRESHOLD = 12\nMIN_MASK_COVERAGE = 0.015\nMAX_MASK_COVERAGE = 0.96\nLANDSCAPE_ASPECT_LIMIT = 1.20\n\n\n@dataclass\nclass ReceiptImagePreprocessingDecision:\n    preprocessing_step: str\n    selected_route: str\n    applied_steps: list[str]\n    fallback_reason: list[str]\n    perspective_normalization: dict[str, Any] | None\n    diagnostics: dict[str, Any] = field(default_factory=dict)\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\ndef _debug_dir() -> Path | None:\n    value = os.environ.get("REZZERV_RECEIPT_PREPROCESS_DEBUG_DIR")\n    if not value:\n        return None\n    path = Path(value)\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\ndef _save_debug(name: str, image: Image.Image, diagnostics: dict[str, Any]) -> None:\n    out = _debug_dir()\n    if out is None:\n        return\n    path = out / name\n    image.save(path)\n    diagnostics.setdefault("debug_files", []).append(str(path))\n\n\ndef _encode_png_from_pil(image: Image.Image) -> bytes:\n    buf = BytesIO()\n    image.save(buf, format="PNG")\n    return buf.getvalue()\n\n\ndef _pil_to_cv(image: Image.Image):\n    if cv2 is None or np is None:\n        return None\n    return cv2.cvtColor(np.array(image.convert("RGB")), cv2.COLOR_RGB2BGR)\n\n\ndef _cv_to_pil(image) -> Image.Image:\n    return Image.fromarray(cv2.cvtColor(image, cv2.COLOR_BGR2RGB))\n\n\ndef _rotate_landscape_pil(image: Image.Image) -> tuple[Image.Image, bool]:\n    if image.height > 0 and (image.width / image.height) >= LANDSCAPE_ASPECT_LIMIT:\n        return image.rotate(90, expand=True), True\n    return image, False\n\n\ndef _crop_alpha_bbox(rgba: Image.Image, diagnostics: dict[str, Any]) -> tuple[Image.Image | None, str | None]:\n    if np is None:\n        return None, "numpy_unavailable"\n\n    alpha = np.array(rgba.getchannel("A"))\n    ys, xs = np.where(alpha > ALPHA_THRESHOLD)\n\n    total = int(alpha.shape[0] * alpha.shape[1])\n    count = int(len(xs))\n    coverage = float(count / total) if total else 0.0\n\n    diagnostics["rembg_alpha"] = {\n        "mask_pixels": count,\n        "total_pixels": total,\n        "coverage": coverage,\n        "threshold": ALPHA_THRESHOLD,\n    }\n\n    _save_debug("10_rembg_alpha_mask.png", Image.fromarray(alpha), diagnostics)\n\n    if count == 0:\n        return None, "rembg_empty_alpha_mask"\n    if coverage < MIN_MASK_COVERAGE:\n        return None, "rembg_mask_coverage_too_low"\n    if coverage > MAX_MASK_COVERAGE:\n        return None, "rembg_mask_coverage_too_high"\n\n    x0, x1 = int(xs.min()), int(xs.max())\n    y0, y1 = int(ys.min()), int(ys.max())\n    w, h = rgba.size\n\n    box_w = x1 - x0 + 1\n    box_h = y1 - y0 + 1\n    pad = max(18, int(min(box_w, box_h) * 0.035))\n\n    x0 = max(0, x0 - pad)\n    y0 = max(0, y0 - pad)\n    x1 = min(w - 1, x1 + pad)\n    y1 = min(h - 1, y1 + pad)\n\n    diagnostics["rembg_bbox"] = {\n        "image_size": [w, h],\n        "bbox": [x0, y0, x1, y1],\n        "bbox_size": [x1 - x0 + 1, y1 - y0 + 1],\n        "crop_reduces_image": (x1 - x0 + 1 < w or y1 - y0 + 1 < h),\n    }\n\n    white = Image.new("RGBA", rgba.size, (255, 255, 255, 255))\n    composed = Image.alpha_composite(white, rgba).convert("RGB")\n    _save_debug("11_rembg_composited_full.png", composed, diagnostics)\n\n    cropped = composed.crop((x0, y0, x1 + 1, y1 + 1))\n    _save_debug("12_rembg_cropped.png", cropped, diagnostics)\n    return cropped, None\n\n\ndef _light_ocr_normalization(image: Image.Image, diagnostics: dict[str, Any]) -> Image.Image:\n    """Small deterministic OCR input cleanup after rembg.\n\n    No aggressive perspective forcing here: if the photo is bad, the quality gate\n    must reject it. Rembg is used only to remove background and crop.\n    """\n    image = ImageOps.exif_transpose(image).convert("RGB")\n    image, rotated = _rotate_landscape_pil(image)\n    if rotated:\n        diagnostics.setdefault("post_rembg_steps", []).append("rotate_landscape_to_portrait")\n\n    if cv2 is None or np is None:\n        return image\n\n    cv = _pil_to_cv(image)\n    if cv is None:\n        return image\n\n    # Limit very large images before OCR; prevents PaddleOCR instability.\n    h, w = cv.shape[:2]\n    max_side = max(w, h)\n    if max_side > 3000:\n        scale = 3000 / float(max_side)\n        cv = cv2.resize(cv, (int(w * scale), int(h * scale)), interpolation=cv2.INTER_AREA)\n        diagnostics.setdefault("post_rembg_steps", []).append("resize_max_side_3000")\n        diagnostics["resized_to"] = [cv.shape[1], cv.shape[0]]\n\n    pil = _cv_to_pil(cv)\n    _save_debug("40_final_runtime_preprocessed.png", pil, diagnostics)\n    return pil\n\n\ndef apply_receipt_image_preprocessing(file_bytes: bytes, filename: str) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    diagnostics: dict[str, Any] = {"filename": filename}\n    suffix = Path(filename or "").suffix.lower()\n\n    if suffix and suffix not in IMAGE_SUFFIXES:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["unsupported_image_suffix"],\n            None,\n            diagnostics,\n        )\n\n    try:\n        original = Image.open(BytesIO(file_bytes))\n        original = ImageOps.exif_transpose(original).convert("RGB")\n        _save_debug("00_input_original.png", original, diagnostics)\n    except Exception as exc:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            [f"image_decode_failed:{type(exc).__name__}"],\n            None,\n            diagnostics,\n        )\n\n    if rembg_remove is None:\n        fallback_img, rotated = _rotate_landscape_pil(original)\n        applied = ["rotate_landscape_to_portrait"] if rotated else []\n        return _encode_png_from_pil(fallback_img), ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "safe_no_rembg",\n            applied,\n            ["rembg_unavailable"],\n            None,\n            diagnostics,\n        )\n\n    try:\n        rgba_bytes = rembg_remove(file_bytes)\n        rgba = Image.open(BytesIO(rgba_bytes)).convert("RGBA")\n        _save_debug("09_rembg_raw_rgba.png", rgba, diagnostics)\n    except Exception as exc:\n        fallback_img, rotated = _rotate_landscape_pil(original)\n        applied = ["rotate_landscape_to_portrait"] if rotated else []\n        return _encode_png_from_pil(fallback_img), ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "safe_rembg_failed",\n            applied,\n            [f"rembg_failed:{type(exc).__name__}"],\n            None,\n            diagnostics,\n        )\n\n    cropped, reason = _crop_alpha_bbox(rgba, diagnostics)\n    if cropped is None:\n        fallback_img, rotated = _rotate_landscape_pil(original)\n        applied = ["rotate_landscape_to_portrait"] if rotated else []\n        return _encode_png_from_pil(fallback_img), ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "safe_rembg_rejected",\n            applied,\n            [reason or "rembg_crop_failed"],\n            None,\n            diagnostics,\n        )\n\n    final_img = _light_ocr_normalization(cropped, diagnostics)\n    diagnostics["final_size"] = [final_img.width, final_img.height]\n\n    return _encode_png_from_pil(final_img), ReceiptImagePreprocessingDecision(\n        "receipt_image_preprocessing",\n        "ai_background_removed_crop",\n        ["ai_background_removed", "alpha_bbox_crop", *diagnostics.get("post_rembg_steps", [])],\n        [],\n        None,\n        diagnostics,\n    )\n', encoding="utf-8")

requirements = req.read_text(encoding="utf-8")
